mapper.insert:
INSERT INTO generation_logs (
    target_date, ai_provider, ai_model, prompt_version,
    generation_prompt_id, validation_prompt_id, status
) VALUES (
    #{targetDate}, #{aiProvider}, #{aiModel}, #{promptVersion},
    #{generationPromptId}, #{validationPromptId}, #{status}
)

INSERT INTO quiz_validation_results (
    generation_log_id, quiz_set_id, attempt_number, validation_type, passed, score, issues_json
) VALUES (
    #{generationLogId}, #{quizSetId}, #{attemptNumber}, #{validationType}, #{passed}, #{score},
    CAST(#{issuesJson} AS JSONB)
)

mapper.select:
SELECT 
FROM generation_logs

    status = #{status}
    AND target_date = #{targetDate}

ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM generation_logs

    status = #{status}
    AND target_date = #{targetDate}

SELECT COUNT(*)
FROM generation_logs
WHERE created_at >= #{from}
  AND created_at < #{until}

mapper.update:
UPDATE ai_api_calls
SET status = #{status}, error_code = #{errorCode}, completed_at = #{completedAt}
WHERE id = #{apiCallId}

mapper.select:
SELECT id AS source_brief_id, target_date, status, model, briefing_text, error_message
FROM source_briefs
WHERE target_date = #{targetDate}

mapper.insert:
INSERT INTO content_sources (
    source_brief_id, passage_position, title, publisher,
    published_on, source_url, summary
) VALUES (
    #{sourceBriefId}, #{passagePosition}, #{title}, #{publisher},
    #{publishedOn}, #{sourceUrl}, #{summary}
)
ON CONFLICT (source_brief_id, source_url) DO NOTHING
